<template><div class="panel"><div class="section-head"><div><h2>{{ t('models.title') }}</h2><p>{{ t('models.description') }}</p></div><el-button type="primary" @click="open()">{{ t('models.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="code" :label="t('common.code')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column prop="modelName" :label="t('models.identifier')"/><el-table-column prop="capabilityLevel" :label="t('models.capability')"/><el-table-column prop="thinkingLevels" :label="t('models.thinkingLevels')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link type="success" @click="startTest(s.row)">{{ t('models.test') }}</el-button><el-button link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('models.edit'):t('models.add')"><el-form label-width="110px"><el-form-item :label="t('common.code')"><el-input v-model="form.code"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item :label="t('models.provider')"><el-select v-model="form.providerId"><el-option v-for="item in providers" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item :label="t('models.identifier')"><el-input v-model="form.modelName"/></el-form-item><el-form-item :label="t('models.capability')"><el-select v-model="form.capabilityLevel"><el-option label="Low" value="LOW"/><el-option label="Medium" value="MIDDLE"/><el-option label="High" value="HIGH"/></el-select></el-form-item><el-form-item :label="t('models.thinkingLevels')"><div class="thinking-levels"><el-input v-for="level in thinkingLevels" :key="level" v-model="thinkingMapping[level]" :placeholder="level"/></div></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog><el-dialog v-model="testVisible" :title="t('models.test')"><el-form><el-form-item :label="t('models.thinkingLevels')"><el-select v-model="testThinkingLevel" clearable :placeholder="t('models.noThinking')"><el-option v-for="level in testLevels" :key="level" :label="level" :value="level"/></el-select></el-form-item></el-form><template #footer><el-button @click="testVisible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="runTest">{{ t('models.test') }}</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';const{t}=useI18n(),rows=ref([]),providers=ref([]),visible=ref(false),testVisible=ref(false),testModel=ref(null),testLevels=ref([]),testThinkingLevel=ref(''),thinkingLevels=['LOW','MEDIUM','HIGH','EXTRA_HIGH','MAX','ULTRA'],form=reactive({id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',thinkingLevels:'',enabled:true}),thinkingMapping=reactive({});function parseMappings(value){const result={};String(value||'').split(/[,\n]/).forEach(item=>{const[key,mapped]=item.split('=',2);if(key&&mapped)result[key.trim().toUpperCase()]=mapped.trim()});return result}function serializeMappings(){return thinkingLevels.filter(level=>thinkingMapping[level]?.trim()).map(level=>`${level}=${thinkingMapping[level].trim()}`).join(',')}async function load(){[rows.value,providers.value]=await Promise.all([http.get('/models').then(r=>r.data),http.get('/models/providers').then(r=>r.data)])}function open(row){Object.assign(form,row?{...row}:{id:null,code:'',name:'',providerId:null,modelName:'',modelType:'TEXT',capabilityLevel:'MIDDLE',thinkingLevels:'',enabled:true});Object.assign(thinkingMapping,{LOW:'',MEDIUM:'',HIGH:'',EXTRA_HIGH:'',MAX:'',ULTRA:'',...parseMappings(form.thinkingLevels)});visible.value=true}async function save(){form.thinkingLevels=serializeMappings();form.id?await http.put(`/models/${form.id}`,form):await http.post('/models',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}function startTest(row){testModel.value=row;testLevels.value=Object.keys(parseMappings(row.thinkingLevels));testThinkingLevel.value='';if(testLevels.value.length)testVisible.value=true;else runTest()}async function runTest(){const result=(await http.post(`/models/${testModel.value.id}/test`,null,{params:testThinkingLevel.value?{thinkingLevel:testThinkingLevel.value}:{}})).data;testVisible.value=false;ElMessage.success(t('models.connected',{duration:result.durationMs}))}onMounted(load)</script>
